const response = $input.item.json;
const currentItem = $('Loop Imágenes').item.json;
const token = 'r8_D4VY9Ay3avB9k5qMARUTqD09qIaiTne3TKVu0';

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function getPrediction(url) {
  const res = await fetch(url, { headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' } });
  if (!res.ok) throw new Error(`Replicate lookup failed (${res.status}): ${await res.text()}`);
  return await res.json();
}

async function resolvePrediction(pred) {
  let cur = pred;
  for (let i = 0; i < 30; i++) {
    if (cur?.error) throw new Error(`Replicate error en ${currentItem.tipo}: ${cur.error}`);
    if (cur?.status === 'failed' || cur?.status === 'canceled') throw new Error(`Replicate ${cur.status}. ID: ${cur.id}`);
    if (cur?.status === 'succeeded' && cur?.output) {
      const imageUrl = Array.isArray(cur.output) ? cur.output[0] : cur.output;
      await sleep(12000);
      return [{ json: { ...currentItem, imageUrl, predictionId: cur.id } }];
    }
    const pollUrl = cur?.urls?.get;
    if (!pollUrl) throw new Error(`Sin output ni poll URL. Status: ${cur?.status || 'unknown'}`);
    await sleep(4000);
    cur = await getPrediction(pollUrl);
  }
  throw new Error(`Replicate timeout para ${currentItem.tipo}`);
}

return await resolvePrediction(response);

const item = $input.item;
const tipo = item.json.tipo || 'imagen';
if (item.binary?.data) {
  item.binary.data.fileName = `${tipo}.png`;
  item.binary.data.mimeType = 'image/png';
}
return { json: { ...item.json, tipo }, binary: item.binary };
